#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int countUniqueBars(int a, int b) {
    int **dp = (int **)malloc(a * sizeof(int *));
    for (int i = 0; i < a; i++) {
        dp[i] = (int *)malloc(b * sizeof(int));
    }

    // Initialize base cases
    for (int i = 0; i < a; i++) {
        dp[i][0] = 1;
    }
    for (int j = 0; j < b; j++) {
        dp[0][j] = 1;
    }

    // Fill up the dp array
    for (int i = 1; i < a; i++) {
        for (int j = 1; j < b; j++) {
            dp[i][j] = (dp[i-1][j] + dp[i][j-1]) % MOD;
        }
    }

    int result = dp[a-1][b-1];
    for (int i = 0; i < a; i++) {
        free(dp[i]);
    }
    free(dp);
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b;
        scanf("%d %d", &a, &b);
        printf("%d\n", countUniqueBars(a, b));
    }
    return 0;
}

