MOD = 1000000007

def count_unique_bars(a, b):
    dp = [[0] * b for _ in range(a)]

    # Initialize base cases
    for i in range(a):
        dp[i][0] = 1
    for j in range(b):
        dp[0][j] = 1

    # Fill up the dp array
    for i in range(1, a):
        for j in range(1, b):
            dp[i][j] = (dp[i-1][j] + dp[i][j-1]) % MOD

    return dp[a-1][b-1]

